(()=>{window.addEventListener("DOMContentLoaded",function(){let e=document.getElementById("dark_mode_btn"),t=document.getElementById("light_mode_btn");localStorage.theme==="dark"||!("theme"in localStorage)&&window.matchMedia("(prefers-color-scheme: dark)").matches?(document.documentElement.classList.add("dark"),t.classList.remove("hidden")):(document.documentElement.classList.remove("dark"),e.classList.remove("hidden")),document.getElementById("header-theme-button").addEventListener("click",function(){document.documentElement.classList.contains("dark")?(localStorage.theme="light",document.documentElement.classList.remove("dark"),t.classList.add("hidden"),e.classList.remove("hidden")):(localStorage.theme="dark",document.documentElement.classList.add("dark"),e.classList.add("hidden"),t.classList.remove("hidden"))})});})();
